// Example: Bicep file with full IntelliSense from the extension
// Type 'res-' + Ctrl+Space for resource snippets

@description('The environment name (dev, staging, prod)')
@allowed(['dev', 'staging', 'prod'])
param environment string = 'dev'

param location string = resourceGroup().location

// Extension provides type checking: storageAccount sku values are enumerated
resource storageAccount 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: 'mystore${uniqueString(resourceGroup().id)}'
  location: location
  sku: {
    name: 'Standard_LRS'    // Ctrl+Space here shows valid SKU options
  }
  kind: 'StorageV2'
  tags: {
    environment: environment
  }
}

output storageAccountName string = storageAccount.name

// Example HTTP trigger function (TypeScript)
// Generated by the VS Code Azure Functions extension
import { app, HttpRequest, HttpResponseInit, InvocationContext } from '@azure/functions';

export async function httpTrigger(
    request: HttpRequest,
    context: InvocationContext
): Promise<HttpResponseInit> {
    context.log(`Processing request: ${request.method} ${request.url}`);

    const name = request.query.get('name') ?? 'World';
    return { body: `Hello, ${name}!` };
}

app.http('httpTrigger', {
    methods: ['GET', 'POST'],
    authLevel: 'anonymous',
    handler: httpTrigger,
});

// launch.json generated by the extension for local debugging
{
  "version": "0.2.0",
  "configurations": [
    {
      "name": "Attach to Node Functions",
      "type": "node",
      "request": "attach",
      "port": 9229,
      "preLaunchTask": "func: host start"
    }
  ]
}

{
  // Azure-wide settings
  "azure.tenant": "your-primary-tenant-id",
  "azure.cloud": "AzureCloud",

  // Azure Functions: use v4 programming model
  "azureFunctions.projectLanguage": "TypeScript",
  "azureFunctions.deploySubpath": ".",

  // Bicep: auto-restore modules on save
  "bicep.enableOutputTimestamp": false,

  // App Service: default web app for quick deploy
  "appService.showDeployConfirmation": true,

  // Storage: confirm before deleting
  "azureStorage.showExplorer": true,

  // Resource Groups: show tags in tree view
  "azureResourceGroups.enableTags": true,

  // Editor: Bicep file associations
  "files.associations": {
    "*.bicep": "bicep",
    "*.bicepparam": "bicep-params"
  }
}

// .devcontainer/devcontainer.json
{
  "name": "Azure Development",
  "image": "mcr.microsoft.com/devcontainers/typescript-node:20",
  "features": {
    "ghcr.io/devcontainers/features/azure-cli:1": {},
    "ghcr.io/devcontainers/features/bicep:1": {},
    "ghcr.io/devcontainers/features/terraform:1": {}
  },
  "customizations": {
    "vscode": {
      "extensions": [
        "ms-azuretools.vscode-azureresourcegroups",
        "ms-azuretools.vscode-bicep",
        "ms-azuretools.vscode-azurefunctions",
        "ms-azuretools.vscode-azureappservice",
        "ms-azuretools.vscode-cosmosdb",
        "ms-azuretools.vscode-azurestorage",
        "ms-vscode.azure-account",
        "GitHub.vscode-github-actions"
      ],
      "settings": {
        "azure.cloud": "AzureCloud"
      }
    }
  },
  "postCreateCommand": "npm install -g azure-functions-core-tools@4 @azure/static-web-apps-cli"
}

// tasks.json — starts the local Functions host
{
  "version": "2.0.0",
  "tasks": [
    {
      "type": "func",
      "label": "func: host start",
      "command": "host start",
      "problemMatcher": "$func-node-watch",
      "isBackground": true,
      "dependsOn": "npm build (functions)"
    },
    {
      "type": "shell",
      "label": "npm build (functions)",
      "command": "npm run build",
      "options": { "cwd": "${workspaceFolder}" }
    }
  ]
}
